import { useAuth } from "../context/AuthContext";

const Dashboard = () => {
  const { user } = useAuth();
  return (
    <div className="bg-white rounded-xl p-6 shadow">
      <h2 className="text-2xl font-semibold">Tableau de bord personnel</h2>
      <p className="mt-2">Bienvenue {user?.prenom} {user?.nom}</p>
      <p className="text-slate-600 mt-1">Vous pouvez gérer vos recherches, favoris et profil.</p>
    </div>
  );
};

export default Dashboard;
